exercise.solution_code:
#include <iostream>
#include <iomanip>

namespace Stats
{
    int runningCount(int add)
    {
        static int count = 0;
        count += add;
        return count;
    }

    int runningSum(int add)
    {
        static int sum = 0;
        sum += add;
        return sum;
    }

    void record(int value)
    {
        runningCount(1);
        runningSum(value);
    }

    void print_stats()
    {
        int count = runningCount(0);
        int sum   = runningSum(0);
        double average = static_cast<double>(sum) / count;
        std::cout << "Count: "   << count << '\n'
                  << "Sum: "     << sum   << '\n'
                  << "Average: " << std::fixed << std::setprecision(2)
                  << average    << '\n';
    }
} // namespace Stats

int main()
{
    int v1{}, v2{}, v3{}, v4{};
    std::cin >> v1 >> v2 >> v3 >> v4;

    Stats::record(v1);
    Stats::record(v2);
    Stats::record(v3);
    Stats::record(v4);

    Stats::print_stats();

    return 0;
}
